import { useState, useEffect, useRef } from "react";

const SpeedyAlphabet = () => {
  const [typedText, setTypedText] = useState("");
  const [startTyping, setStartTyping] = useState(false);
  const [startTime, setStartTime] = useState(null);
  const [elapsedTime, setElapsedTime] = useState("0.00");
  const [timerRunning, setTimerRunning] = useState(false);
  const intervalRef = useRef(null);
  const inputRef = useRef(null);
  const [alphabetTimes, setAlphabetTimes] = useState([]);
  const [highScores, setHighScores] = useState([]); // Initialize state for leaderboard scores
  const [loading, setLoading] = useState(true); // Loading state for async fetch

  useEffect(() => {
    // Fetch the leaderboard when the component is mounted
    const fetchLeaderboard = async () => {
      try {
        const response = await fetch(
          "https://a-to-z-server-oa7r.onrender.com/api/scores",
        );
        if (response.ok) {
          const scores = await response.json();
          console.log("Fetched scores:", scores); // Log to verify the response

          // Sort the scores by time (ascending) and take the top 3
          const topScores = scores.sort((a, b) => a.time - b.time).slice(0, 3);
          setHighScores(topScores); // Set the top 3 scores to state
        } else {
          console.error("Failed to fetch leaderboard");
        }
      } catch (error) {
        console.error("Error fetching leaderboard:", error);
      } finally {
        setLoading(false); // Set loading to false after fetching
      }
    };

    fetchLeaderboard();

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, []);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  useEffect(() => {
    const handleKey = (e) => {
      if (e.key === "Tab") {
        e.preventDefault();
        handleReset();
        inputRef.current?.focus();
      }
    };

    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, []);

  const startTimer = (startTs) => {
    if (!timerRunning) {
      const now = startTs ?? Date.now();
      setStartTime(now);
      setTimerRunning(true);
      intervalRef.current = setInterval(() => {
        setElapsedTime(((Date.now() - now) / 1000).toFixed(2));
      }, 16);
    }
  };

  const stopTimer = () => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setTimerRunning(false);
  };

  const handleInputChange = (e) => {
    const inputValue = e.target.value;

    if (inputValue.length > 0) {
      const currentChar = inputValue[inputValue.length - 1].toLowerCase();

      if (!startTyping && inputValue.length > 0) {
        setStartTyping(true);
      }

      if (typedText.length === 0) {
        setElapsedTime("0.00");
      }

      if (currentChar === nextExpectedChar()) {
        let baseTime = startTime;

        if (!timerRunning) {
          const now = Date.now();
          startTimer(now);
          baseTime = now;
        }

        const currentTime = (Date.now() - baseTime) / 1000;

        setAlphabetTimes((prevTimes) => [...prevTimes, currentTime]);

        if (inputValue === "abcdefghijklmnopqrstuvwxyz") {
          stopTimer();
          const totalTime = (Date.now() - (startTime ?? Date.now())) / 1000;
          setElapsedTime(totalTime.toFixed(2));
          updateHighScores(totalTime); // Check if this score qualifies for top 3
        }

        setTypedText(inputValue);
      } else {
        // ignore wrong input but keep cursor responsive
        return;
      }
    } else {
      setStartTyping(false);
    }
  };

  const nextExpectedChar = () => {
    const alphabet = "abcdefghijklmnopqrstuvwxyz";
    return alphabet[typedText.length];
  };

  const updateHighScores = (newTime) => {
    const qualifiesForTop3 =
      highScores.length < 3 ||
      parseFloat(newTime) < parseFloat(highScores[2]?.time);

    if (qualifiesForTop3) {
      const newScore = { name: "You", time: parseFloat(newTime) };

      const updatedScores = [...highScores, newScore]
        .sort((a, b) => a.time - b.time)
        .slice(0, 3);

      setHighScores(updatedScores);
    }
  };

  const handleReset = () => {
    setTypedText("");
    setElapsedTime("0.00");
    setStartTime(null);
    setTimerRunning(false);
    setStartTyping(false);
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setAlphabetTimes([]);
  };

  return (
    <div className="min-h-screen bg-gray-100 text-gray-800 px-6 py-8">
      {/* HEADER */}
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-2xl font-bold tracking-wide">ALPHATYPE</h1>
        <div className="flex gap-6 text-sm font-medium text-gray-500">
          <span className="text-blue-600">Dashboard</span>
          <span>Practice</span>
          <span>Leaderboards</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* LEFT PANEL */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-5 rounded-lg shadow">
            <p className="text-xs text-gray-500">CURRENT SPEED</p>
            <h2 className="text-3xl font-bold text-blue-600">84 WPM</h2>
          </div>

          <div className="bg-white p-5 rounded-lg shadow">
            <p className="text-xs text-gray-500">ACCURACY</p>
            <h2 className="text-3xl font-bold text-green-600">98.4%</h2>
          </div>

          <div className="bg-white p-5 rounded-lg shadow">
            <p className="text-xs text-gray-500 mb-2">LEADERBOARD</p>
            {loading ? (
              <p className="text-sm text-gray-400">Loading...</p>
            ) : (
              highScores.map((entry, i) => (
                <div key={i} className="flex justify-between text-sm mb-1">
                  <span>{entry.name}</span>
                  <span>{entry.time.toFixed(2)}s</span>
                </div>
              ))
            )}
          </div>
        </div>

        {/* MAIN TYPING AREA */}
        <div
          className="lg:col-span-3 bg-gray-200 rounded-lg p-10 shadow-inner cursor-text"
          onClick={() => inputRef.current?.focus()}
        >
          <div className="flex justify-between mb-4 text-sm text-gray-500">
            <span>Timer: {elapsedTime}s</span>
            <span>Typed: {typedText.length}/26</span>
          </div>

          <div className="text-4xl sm:text-6xl font-light tracking-widest text-gray-600 leading-relaxed text-center">
            {"abcdefghijklmnopqrstuvwxyz".split("").map((letter, index) => {
              const isDone = index < typedText.length;
              const isNext = index === typedText.length;

              return (
                <span
                  key={index}
                  className={`${
                    isDone
                      ? "text-gray-900"
                      : isNext
                        ? "text-black underline"
                        : "text-gray-400"
                  } mr-2`}
                >
                  {letter}
                </span>
              );
            })}
          </div>

          <input
            ref={inputRef}
            type="text"
            value={typedText}
            onChange={handleInputChange}
            className="opacity-0 absolute pointer-events-none"
            autoFocus
          />

          <div className="text-center mt-6 text-xs text-gray-500">
            Press TAB to restart
          </div>
        </div>
      </div>
    </div>
  );
};

export default SpeedyAlphabet;
